
-- إزالة الجدول القديم بالكامل لتنظيف المساحة
DROP TABLE IF EXISTS profiles;

-- إنشاء الجدول الجديد العملاق بجميع الحقول الجديدة مع (المدينة)
CREATE TABLE profiles (
    id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
    name TEXT NOT NULL,
    specialization TEXT NOT NULL CHECK (specialization IN ('مدرس', 'مدرب', 'محفظ')),
    subject TEXT NOT NULL,
    target_audience TEXT[] NOT NULL,
    session_type TEXT NOT NULL CHECK (session_type IN ('أونلاين', 'أوفلاين', 'كلاهما')),
    bio TEXT NOT NULL,
    years_of_experience INTEGER NOT NULL DEFAULT 0,
    rating NUMERIC(2,1) NOT NULL DEFAULT 5.0,
    whatsapp_link TEXT NOT NULL,
    facebook_link TEXT,
    profile_picture TEXT NOT NULL,
    random_glow_color TEXT,
    skills TEXT[] DEFAULT '{}'::TEXT[],
    achievements TEXT[] DEFAULT '{}'::TEXT[],
    video_intro_url TEXT,
    city TEXT NOT NULL,
    created_at TIMESTAMP WITH TIME ZONE DEFAULT TIMEZONE('utc'::text, NOW()) NOT NULL
);

-- التفعيل الإجباري لقوانين الحماية RLS (كما طلبت لضمان التفعيل)
ALTER TABLE profiles ENABLE ROW LEVEL SECURITY;

-- صناعة القوانين
CREATE POLICY "Allow public read access" ON profiles FOR SELECT USING (true);
CREATE POLICY "Allow authenticated users to manage profiles" ON profiles FOR ALL USING (auth.role() = 'authenticated');

-- إدخال الـ 30 شخصية بالبيانات الحصرية الجديدة
